    private String eventType;

    @NotNull(message = "Payload must not be null")
    @Size(max = 10000, message = "Payload must not exceed 10000 characters")
    private String payload;

    private String source;
    private Instant timestamp;

    public Event() {
        this.id = UUID.randomUUID().toString();
        this.timestamp = Instant.now();
    }

    public Event(String eventType, String payload, String source) {
        this();
        this.eventType = sanitize(eventType);
        this.payload = sanitize(payload);
        this.source = sanitize(source);
    }

    private String sanitize(String input) {
        if (input == null) {
            return null;
        }
        // Remove control characters and trim
        return input.replaceAll("[\\p{Cntrl}&&[^\n\r\t]]", "").trim();
    }

    public String getId() { return id; }
    public void setId(String id) { this.id = id; }
    public String getEventType() { return eventType; }
    public void setEventType(String eventType) { this.eventType = sanitize(eventType); }
    public String getPayload() { return payload; }
    public void setPayload(String payload) { this.payload = sanitize(payload); }
    public String getSource() { return source; }
