package com.eventplatform.service;

import com.eventplatform.model.Event;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.SendResult;
import org.springframework.stereotype.Service;

import java.util.concurrent.CompletableFuture;

@Service
public class EventProducerService {

    private static final Logger logger = LoggerFactory.getLogger(EventProducerService.class);
    private static final String TOPIC = "events";

    private final KafkaTemplate<String, Event> kafkaTemplate;

    public EventProducerService(KafkaTemplate<String, Event> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public CompletableFuture<SendResult<String, Event>> publishEvent(Event event) {
        if (event == null || event.getEventType() == null || event.getEventType().isBlank()) {
            throw new IllegalArgumentException("Event and event type must not be null or blank");
        }

        logger.info("Publishing event: id={}, type={}", event.getId(), event.getEventType());

        CompletableFuture<SendResult<String, Event>> future =
                kafkaTemplate.send(TOPIC, event.getId(), event);

        future.whenComplete((result, ex) -> {
            if (ex != null) {
                logger.error("Failed to publish event: id={}, type={}, error={}",
                        event.getId(), event.getEventType(), ex.getMessage());
            } else {
                logger.info("Event published successfully: id={}, type={}, partition={}, offset={}",
                        event.getId(),
                        event.getEventType(),
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            }
        });

        return future;
    }

    public CompletableFuture<SendResult<String, Event>> publishEventToTopic(String topic, Event event) {
        if (topic == null || topic.isBlank()) {
            throw new IllegalArgumentException("Topic must not be null or blank");
        }
        if (event == null || event.getEventType() == null || event.getEventType().isBlank()) {
            throw new IllegalArgumentException("Event and event type must not be null or blank");
        }

        // Validate topic name to prevent injection
        if (!topic.matches("^[a-zA-Z0-9._-]+$")) {
            throw new IllegalArgumentException("Invalid topic name");
        }

        logger.info("Publishing event to topic {}: id={}, type={}", topic, event.getId(), event.getEventType());

        return kafkaTemplate.send(topic, event.getId(), event);
    }
}

