package com.eventplatform.service;

import com.eventplatform.model.Event;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.kafka.support.KafkaHeaders;
import org.springframework.messaging.handler.annotation.Header;
import org.springframework.messaging.handler.annotation.Payload;
import org.springframework.stereotype.Service;

@Service
public class EventConsumerService {

    private static final Logger logger = LoggerFactory.getLogger(EventConsumerService.class);

    private final EventProcessingService eventProcessingService;

    public EventConsumerService(EventProcessingService eventProcessingService) {
        this.eventProcessingService = eventProcessingService;
    }

    @KafkaListener(
            topics = "events",
            groupId = "${spring.kafka.consumer.group-id:event-platform-group}",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeEvent(
            @Payload Event event,
            @Header(KafkaHeaders.RECEIVED_TOPIC) String topic,
            @Header(KafkaHeaders.RECEIVED_PARTITION) int partition,
            @Header(KafkaHeaders.OFFSET) long offset,
            @Header(KafkaHeaders.RECEIVED_KEY) String key) {

        logger.info("Received event: id={}, type={}, topic={}, partition={}, offset={}",
                event.getId(), event.getEventType(), topic, partition, offset);

        try {
            validateEvent(event);
            eventProcessingService.processEvent(event);
            logger.info("Event processed successfully: id={}", event.getId());
        } catch (IllegalArgumentException e) {
            logger.warn("Invalid event received, skipping: id={}, error={}", event.getId(), e.getMessage());
            // Don't rethrow - skip invalid messages
        } catch (Exception e) {
            logger.error("Error processing event: id={}, error={}", event.getId(), e.getMessage());
            throw e; // Rethrow to trigger retry via error handler
        }
    }

    @KafkaListener(
            topics = "events.retry",
            groupId = "${spring.kafka.consumer.group-id:event-platform-group}-retry",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeRetryEvent(
            @Payload Event event,
            @Header(KafkaHeaders.RECEIVED_TOPIC) String topic,
            @Header(KafkaHeaders.OFFSET) long offset) {

        logger.info("Received retry event: id={}, type={}, topic={}, offset={}",
                event.getId(), event.getEventType(), topic, offset);

        try {
            validateEvent(event);
            eventProcessingService.processEvent(event);
            logger.info("Retry event processed successfully: id={}", event.getId());
        } catch (Exception e) {
            logger.error("Failed to process retry event: id={}, error={}", event.getId(), e.getMessage());
            // Could send to DLQ here
        }
    }

    @KafkaListener(
            topics = "events.dlq",
            groupId = "${spring.kafka.consumer.group-id:event-platform-group}-dlq",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeDlqEvent(
            @Payload Event event,
            @Header(KafkaHeaders.RECEIVED_TOPIC) String topic,
            @Header(KafkaHeaders.OFFSET) long offset) {

        logger.warn("Received DLQ event: id={}, type={}, topic={}, offset={}",
                event.getId(), event.getEventType(), topic, offset);
        // Log for manual investigation
    }

    private void validateEvent(Event event) {
        if (event == null) {
            throw new IllegalArgumentException("Event must not be null");
        }
        if (event.getId() == null || event.getId().isBlank()) {
            throw new IllegalArgumentException("Event ID must not be null or blank");
        }
        if (event.getEventType() == null || event.getEventType().isBlank()) {
            throw new IllegalArgumentException("Event type must not be null or blank");
        }
        if (event.getEventType().length() > 255) {
            throw new IllegalArgumentException("Event type exceeds maximum length");
        }
        if (event.getPayload() != null && event.getPayload().length() > 10000) {
            throw new IllegalArgumentException("Payload exceeds maximum length");
        }
    }
}

