package com.eventplatform.service;

import com.eventplatform.model.Event;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

@Service
public class EventProcessingService {

    private static final Logger logger = LoggerFactory.getLogger(EventProcessingService.class);

    public void processEvent(Event event) {
        logger.info("Processing event: id={}, type={}, source={}, timestamp={}",
                event.getId(), event.getEventType(), event.getSource(), event.getTimestamp());

        switch (event.getEventType()) {
            case "USER_CREATED":
                handleUserCreated(event);
                break;
            case "ORDER_PLACED":
                handleOrderPlaced(event);
                break;
            case "PAYMENT_PROCESSED":
                handlePaymentProcessed(event);
                break;
            default:
                logger.info("Handling generic event type: {}", event.getEventType());
                handleGenericEvent(event);
                break;
        }
    }

    private void handleUserCreated(Event event) {
        logger.info("Processing USER_CREATED event: id={}", event.getId());
        // Business logic for user creation
    }

    private void handleOrderPlaced(Event event) {
        logger.info("Processing ORDER_PLACED event: id={}", event.getId());
        // Business logic for order placement
    }

    private void handlePaymentProcessed(Event event) {
        logger.info("Processing PAYMENT_PROCESSED event: id={}", event.getId());
        // Business logic for payment processing
    }

    private void handleGenericEvent(Event event) {
        logger.info("Processing generic event: id={}, type={}", event.getId(), event.getEventType());
    }
}

