package com.eventplatform.controller;

import com.eventplatform.model.Event;
import com.eventplatform.service.EventProducerService;
import jakarta.validation.Valid;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.TimeoutException;

@RestController
@RequestMapping("/api/v1/events")
public class EventController {

    private static final Logger logger = LoggerFactory.getLogger(EventController.class);

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping
    public ResponseEntity<Map<String, Object>> publishEvent(@Valid @RequestBody Event event) {
        try {
            var result = eventProducerService.publishEvent(event)
                    .get(10, TimeUnit.SECONDS);

            Map<String, Object> response = Map.of(
                    "status", "SUCCESS",
                    "eventId", event.getId(),
                    "topic", result.getRecordMetadata().topic(),
                    "partition", result.getRecordMetadata().partition(),
                    "offset", result.getRecordMetadata().offset()
            );

            return ResponseEntity.status(HttpStatus.CREATED).body(response);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            logger.error("Interrupted while publishing event", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("status", "ERROR", "message", "Publishing was interrupted"));
        } catch (ExecutionException e) {
            logger.error("Failed to publish event", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("status", "ERROR", "message", "Failed to publish event"));
        } catch (TimeoutException e) {
            logger.error("Timeout while publishing event", e);
            return ResponseEntity.status(HttpStatus.GATEWAY_TIMEOUT)
                    .body(Map.of("status", "ERROR", "message", "Publishing timed out"));
        }
    }

    @PostMapping("/async")
    public ResponseEntity<Map<String, String>> publishEventAsync(@Valid @RequestBody Event event) {
        eventProducerService.publishEvent(event);
        return ResponseEntity.accepted()
                .body(Map.of("status", "ACCEPTED", "eventId", event.getId()));
    }

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<Map<String, String>> handleIllegalArgument(IllegalArgumentException e) {
        return ResponseEntity.badRequest()
                .body(Map.of("status", "ERROR", "message", e.getMessage()));
    }
}

